mapper.update:
update agent_token
name = #{name,jdbcType=VARCHAR}, project_id = #{projectId,jdbcType=VARCHAR}, scopes = #{scopes,jdbcType=VARCHAR}, expire_time = #{expireTime,jdbcType=BIGINT}, enable = #{enable,jdbcType=BIT},
